PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE IF NOT EXISTS "app_state_legacy" (   id TEXT PRIMARY KEY,   state_json TEXT NOT NULL,   schema_version INTEGER NOT NULL DEFAULT 12,   updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,   updated_by TEXT );
CREATE TABLE IF NOT EXISTS "audit_log_legacy" (   id INTEGER PRIMARY KEY AUTOINCREMENT,   actor_email TEXT,   action TEXT NOT NULL,   entity_type TEXT,   entity_id TEXT,   before_json TEXT,   after_json TEXT,   metadata_json TEXT,   created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS "app_users_legacy" (   email TEXT PRIMARY KEY,   name TEXT,   role TEXT NOT NULL DEFAULT 'viewer',   active INTEGER NOT NULL DEFAULT 1,   created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE app_state (
    tenant_id TEXT NOT NULL,
    state_key TEXT NOT NULL,
    state_json TEXT NOT NULL,
    version INTEGER NOT NULL DEFAULT 1,
    updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_by TEXT,
    PRIMARY KEY (tenant_id, state_key)
  );
CREATE TABLE audit_log (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    tenant_id TEXT NOT NULL,
    actor_email TEXT,
    action TEXT NOT NULL,
    entity_type TEXT,
    entity_id TEXT,
    metadata_json TEXT,
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
  );
CREATE TABLE app_users (
    email TEXT PRIMARY KEY,
    display_name TEXT,
    role TEXT NOT NULL DEFAULT 'viewer',
    active INTEGER NOT NULL DEFAULT 1,
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
  );
DELETE FROM sqlite_sequence;
